+/**
+ * Pure validation functions for user operations.
+ *
+ * No side effects, no database calls — can be reused across services.
+ */
+
+import type { CreateUserInput, UpdateUserInput } from '../models/user.js';
+import { isValidEmail } from './email.validator.js';
+
+/**
+ * Validate input for creating a user.
+ * Returns an error message if invalid, or null if valid.
+ */
+export function validateCreateUserInput(input: CreateUserInput): string | null {
+  if (!input.name || input.name.trim().length === 0) {
+    return 'User name is required';
+  }
+  if (!input.email || input.email.trim().length === 0) {
+    return 'User email is required';
+  }
+  if (!isValidEmail(input.email)) {
+    return `Invalid email format: ${input.email}`;
+  }
+  return null;
+}
+
+/**
+ * Validate input for updating a user.
+ * Returns an error message if invalid, or null if valid.
+ */
+export function validateUpdateUserInput(input: UpdateUserInput): string | null {
+  if (input.email !== undefined && !isValidEmail(input.email)) {
+    return `Invalid email format: ${input.email}`;
+  }
+  if (input.name !== undefined && input.name.trim().length === 0) {
+    return 'User name cannot be empty';
+  }
+  return null;
+}
+
+/**
+ * Determine which fields changed between existing and update input.
+ */
+export function detectUserChanges(
+  existing: { name: string; email: string; role: string },
+  input: UpdateUserInput,
+): string[] {
+  const changes: string[] = [];
+  if (input.name && input.name !== existing.name) changes.push('name');
+  if (input.email && input.email !== existing.email) changes.push('email');
+  if (input.role && input.role !== existing.role) changes.push('role');
+  return changes;
+}

