      ).toBeNull();
    });

    it('should return error for empty items', () => {
      expect(validateOrderItems([])).toBe('Order must have at least one item');
    });

    it('should return null for multiple items', () => {
      expect(
        validateOrderItems([
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          { productId: 'p2', name: 'Gadget', quantity: 2, unitPrice: 20 },
        ]),
      ).toBeNull();
    });
  });
});

import { describe, it, expect } from 'vitest';
import { isValidEmail, normalizeEmail } from '../../src/validators/email.validator.js';

describe('Email Validators', () => {
  describe('isValidEmail', () => {
    it('should accept valid email', () => {
      expect(isValidEmail('user@example.com')).toBe(true);
    });

    it('should accept email with subdomain', () => {
      expect(isValidEmail('user@mail.example.com')).toBe(true);
    });

    it('should reject missing @', () => {
      expect(isValidEmail('userexample.com')).toBe(false);
    });

    it('should reject missing domain', () => {
      expect(isValidEmail('user@')).toBe(false);
    });

    it('should reject missing local part', () => {
      expect(isValidEmail('@example.com')).toBe(false);
    });

    it('should reject spaces', () => {
      expect(isValidEmail('user @example.com')).toBe(false);
    });

    it('should reject empty string', () => {
      expect(isValidEmail('')).toBe(false);
    });
  });

  describe('normalizeEmail', () => {
    it('should lowercase email', () => {
      expect(normalizeEmail('User@Example.COM')).toBe('user@example.com');
    });

    it('should trim whitespace', () => {
      expect(normalizeEmail('  user@example.com  ')).toBe('user@example.com');
    });

    it('should handle already normalized email', () => {
      expect(normalizeEmail('user@example.com')).toBe('user@example.com');
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateCreateUserInput,
  validateUpdateUserInput,
  detectUserChanges,
} from '../../src/validators/user.validator.js';

describe('User Validators', () => {
  describe('validateCreateUserInput', () => {
    it('should return null for valid input', () => {
      expect(
        validateCreateUserInput({
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
        }),
      ).toBeNull();
    });

    it('should reject empty name', () => {
      expect(
        validateCreateUserInput({
          name: '',
          email: 'alice@example.com',
          role: 'member',
        }),
      ).toBe('User name is required');
    });

    it('should reject whitespace-only name', () => {
      expect(
        validateCreateUserInput({
          name: '   ',
          email: 'alice@example.com',
          role: 'member',
        }),
      ).toBe('User name is required');
    });

    it('should reject empty email', () => {
      expect(
        validateCreateUserInput({
          name: 'Alice',
          email: '',
          role: 'member',
        }),
      ).toBe('User email is required');
    });

    it('should reject invalid email format', () => {
      expect(
        validateCreateUserInput({
          name: 'Alice',
          email: 'not-an-email',
          role: 'member',
        }),
      ).toBe('Invalid email format: not-an-email');
    });
  });

  describe('validateUpdateUserInput', () => {
    it('should return null for valid input', () => {
      expect(validateUpdateUserInput({ name: 'Alice' })).toBeNull();
    });

    it('should return null for empty input', () => {
      expect(validateUpdateUserInput({})).toBeNull();
    });

    it('should reject invalid email format', () => {
      expect(validateUpdateUserInput({ email: 'bad-email' })).toBe(
        'Invalid email format: bad-email',
      );
    });

    it('should reject empty name', () => {
      expect(validateUpdateUserInput({ name: '' })).toBe(
        'User name cannot be empty',
      );
    });

    it('should accept valid email', () => {
      expect(
        validateUpdateUserInput({ email: 'alice@example.com' }),
      ).toBeNull();
    });
  });

  describe('detectUserChanges', () => {
    const existing = { name: 'Alice', email: 'alice@example.com', role: 'member' };

    it('should detect name change', () => {
      expect(detectUserChanges(existing, { name: 'Bob' })).toEqual(['name']);
    });

    it('should detect email change', () => {
      expect(detectUserChanges(existing, { email: 'bob@example.com' })).toEqual(
        ['email'],
      );
    });

    it('should detect role change', () => {
      expect(detectUserChanges(existing, { role: 'admin' })).toEqual(['role']);
    });

    it('should detect multiple changes', () => {
      expect(
        detectUserChanges(existing, { name: 'Bob', email: 'bob@example.com' }),
      ).toEqual(['name', 'email']);
    });

    it('should return empty array when nothing changed', () => {
      expect(detectUserChanges(existing, {})).toEqual([]);
    });

    it('should return empty when values are the same', () => {
      expect(
        detectUserChanges(existing, { name: 'Alice', email: 'alice@example.com' }),
      ).toEqual([]);
    });
  });
});
